import { BrowserModule } from '@angular/platform-browser';
import { NgModule } from '@angular/core';

import { AppComponent } from './app.component';
import { NxModule } from '@nrwl/nx';
import { RouterModule } from '@angular/router';
import {
  balambFrontGateRoutes,
  BalambFrontGateModule
} from '@foundation/balamb/front-gate';
import { FoundationModule } from '@foundation/foundation';

@NgModule({
  declarations: [AppComponent],
  imports: [
    BrowserModule,
    NxModule.forRoot(),
    BalambFrontGateModule,
    FoundationModule,
    RouterModule.forRoot(
      [
        { path: '', children: balambFrontGateRoutes },
        {
          path: 'balamb-garden',
          loadChildren: '@foundation/balamb/garden#BalambGardenModule'
        },
        {
          path: 'balamb-admin',
          loadChildren: '@foundation/balamb/admin#BalambAdminModule'
        }
      ],
      {
        initialNavigation: 'enabled'
      }
    )
  ],
  providers: [],
  bootstrap: [AppComponent]
})
export class AppModule {}
