import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Route } from '@angular/router';
import { GateComponent } from './gate/gate.component';
import { ArrivalComponent } from './arrival/arrival.component';

export const balambFrontGateRoutes: Route[] = [
  {
    path: '',
    component: ArrivalComponent
  },
  {
    path: 'gate',
    component: GateComponent
  }
];

@NgModule({
  imports: [CommonModule, RouterModule.forChild(balambFrontGateRoutes)],
  declarations: [GateComponent, ArrivalComponent],
  exports: [RouterModule]
})
export class BalambFrontGateModule {}
